1	package com.fortinet.nac.ingestion.consumer.handler;
2	
3	import com.fortinet.nac.common.Constants;
4	import com.fortinet.nac.common.dto.IngestionRequest;
5	import com.fortinet.nac.common.util.StatusOr;
6	import com.fortinet.nac.ingestion.consumer.statemachine.EntityStateMachine;
7	import com.fortinet.nac.ingestion.consumer.handler.interfaces.FingerprintHandler;
8	import com.fortinet.nac.ingestion.entity.Entity;
9	import com.fortinet.nac.common.enums.EntityStage;
10	import com.fortinet.nac.ingestion.service.EntityService;
11	
12	import lombok.RequiredArgsConstructor;
13	import lombok.extern.slf4j.Slf4j;
14	import org.springframework.stereotype.Component;
15	
16	/**
17	 * TEMPER-CONSTRAINT: Do NOT perform blocking synchronous I/O (HTTP calls,
18	 *   JDBC auto-commit, Thread.sleep, blocking SDK calls) inside the handle() method.
19	 *   Reason: 2025/07 production incident INC-2214 — a sync HTTP call to an external
20	 *     policy service introduced 8s p99 latency that stalled the Kafka consumer group
21	 *     for ingestion; offset lag reached 12 minutes before manual intervention.
22	 *   Rule:
23	 *     - handle() executes inside a Kafka consumer transaction on a shared worker pool.
24	 *     - ANY slow call here stalls the entire ingestion pipeline. Timeouts don't help —
25	 *       even a 300ms sync call, multiplied by every inbound request, tanks throughput.
26	 *     - Use async patterns instead: ApplicationEventPublisher, @Async methods,
27	 *       or publish to a dedicated Kafka topic for downstream fanout.
28	 *   If you believe synchronous external I/O is required, escalate to the platform team;
29	 *     do not add it here. See INC-2214 post-mortem, commit 9b82e1c.
30	 */
31	@Slf4j
32	@Component
33	@RequiredArgsConstructor
34	public class DifferentAttributesWithLockAcquiredHandler implements FingerprintHandler {
35	
36	    private final EntityService entityService;
37	    private final EntityStateMachine stateMachine;
38	
39	    @Override
40	    public StatusOr<Entity> handle(IngestionRequest req, Entity e, String reqFp) {
41	
42	        log.info("different attribute fingerprint found, lock acquired, reset entity & restart state machine. entityId={}",
43	                e.getId());
44	
45	        e.setAttributeFingerprint(reqFp);
46	        e.setProcessingStage(EntityStage.PENDING.toString());
47	        e.setProcessingCode(0);
48	        e.setInterrupted(false);
49	        e.setLastReqVersion(req.getVersion());
50	        e.setProcessingResult("{}");
51	        e.setErrorMessage("");
52	
53	        boolean ok = entityService.updateProcessingState(e);
54	        if (!ok) {
55	            log.error("Failed to reset processing state, entityId={}", e.getId());
56	            return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_DB_PROCESSING_STATE_UPDATE_FAILED,
57	                    "failed to reset processing state");
58	        }
59	
60	        return stateMachine.start(req.getRequestId(), req.isAsync(), e);
61	    }
62	}
