3	import org.springframework.beans.factory.annotation.Value;
4	import org.springframework.context.annotation.Bean;
5	import org.springframework.context.annotation.Configuration;
6	import org.springframework.scheduling.concurrent.ThreadPoolTaskExecutor;
7	
8	import java.util.concurrent.Executor;
9	import java.util.concurrent.ThreadPoolExecutor;
10	
11	@Configuration
12	public class PolicyReprocessAsyncConfig {
13	
14	    @Value("${policy.reprocess.listener.core-size:1}")
15	    private int listenerCoreSize;
16	
17	    @Value("${policy.reprocess.listener.max-size:2}")
18	    private int listenerMaxSize;
19	
20	    @Value("${policy.reprocess.listener.queue-capacity:100}")
21	    private int listenerQueueCapacity;
22	
23	    @Value("${policy.reprocess.listener.keep-alive-seconds:60}")
24	    private int listenerKeepAliveSeconds;
25	
26	    @Value("${policy.reprocess.job.core-size:8}")
27	    private int jobCoreSize;
28	
29	    @Value("${policy.reprocess.job.max-size:16}")
30	    private int jobMaxSize;
31	
32	    @Value("${policy.reprocess.job.queue-capacity:32}")
33	    private int jobQueueCapacity;
34	
35	    @Value("${policy.reprocess.job.keep-alive-seconds:60}")
36	    private int jobKeepAliveSeconds;
37	
38	    @Bean("policyReprocessListenerExecutor")
39	    public Executor policyReprocessListenerExecutor() {
40	        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
41	        executor.setCorePoolSize(listenerCoreSize);
42	        executor.setMaxPoolSize(listenerMaxSize);
43	        executor.setQueueCapacity(listenerQueueCapacity);
44	        executor.setKeepAliveSeconds(listenerKeepAliveSeconds);
45	        executor.setThreadNamePrefix("policy-reprocess-listener-");
46	        executor.setRejectedExecutionHandler(new ThreadPoolExecutor.CallerRunsPolicy());
47	        executor.initialize();
48	        return executor;
49	    }
50	
51	    @Bean("policyReprocessJobExecutor")
52	    public Executor policyReprocessJobExecutor() {
53	        int effectiveCoreSize = Math.max(1, jobCoreSize);
54	        int effectiveMaxSize = Math.max(effectiveCoreSize, jobMaxSize);
55	        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
56	        executor.setCorePoolSize(effectiveCoreSize);
57	        executor.setMaxPoolSize(effectiveMaxSize);
58	        executor.setQueueCapacity(jobQueueCapacity);
59	        executor.setKeepAliveSeconds(jobKeepAliveSeconds);
60	        executor.setThreadNamePrefix("policy-reprocess-job-");
61	        executor.setRejectedExecutionHandler(new ThreadPoolExecutor.CallerRunsPolicy());
62	        executor.initialize();
63	        return executor;
64	    }
65	}
