package com.fortinet.nac.ingestion.config;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.scheduling.concurrent.ThreadPoolTaskExecutor;

import java.util.concurrent.Executor;
import java.util.concurrent.ThreadPoolExecutor;

@Configuration
public class PolicyReprocessAsyncConfig {

    @Value("${policy.reprocess.listener.core-size:1}")
    private int listenerCoreSize;

    @Value("${policy.reprocess.listener.max-size:2}")
    private int listenerMaxSize;

    @Value("${policy.reprocess.listener.queue-capacity:100}")
    private int listenerQueueCapacity;

    @Value("${policy.reprocess.listener.keep-alive-seconds:60}")
    private int listenerKeepAliveSeconds;

    @Value("${policy.reprocess.job.core-size:8}")
    private int jobCoreSize;

    @Value("${policy.reprocess.job.max-size:16}")
    private int jobMaxSize;

    @Value("${policy.reprocess.job.queue-capacity:32}")
    private int jobQueueCapacity;

    @Value("${policy.reprocess.job.keep-alive-seconds:60}")
    private int jobKeepAliveSeconds;

    @Bean("policyReprocessListenerExecutor")
    public Executor policyReprocessListenerExecutor() {
        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
        executor.setCorePoolSize(listenerCoreSize);
        executor.setMaxPoolSize(listenerMaxSize);
        executor.setQueueCapacity(listenerQueueCapacity);
        executor.setKeepAliveSeconds(listenerKeepAliveSeconds);
        executor.setThreadNamePrefix("policy-reprocess-listener-");
        executor.setRejectedExecutionHandler(new ThreadPoolExecutor.CallerRunsPolicy());
        executor.initialize();
        return executor;
    }

    @Bean("policyReprocessJobExecutor")
    public Executor policyReprocessJobExecutor() {
        int effectiveCoreSize = Math.max(1, jobCoreSize);
        int effectiveMaxSize = Math.max(effectiveCoreSize, jobMaxSize);
        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
        executor.setCorePoolSize(effectiveCoreSize);
        executor.setMaxPoolSize(effectiveMaxSize);
        executor.setQueueCapacity(jobQueueCapacity);
        executor.setKeepAliveSeconds(jobKeepAliveSeconds);
        executor.setThreadNamePrefix("policy-reprocess-job-");
        executor.setRejectedExecutionHandler(new ThreadPoolExecutor.CallerRunsPolicy());
        executor.initialize();
        return executor;
    }
}

