package com.fortinet.nac.ingestion.config;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.client.SimpleClientHttpRequestFactory;
import org.springframework.scheduling.concurrent.ThreadPoolTaskExecutor;
import org.springframework.web.client.RestTemplate;

import java.util.concurrent.Executor;
import java.util.concurrent.ThreadPoolExecutor;

@Configuration
public class PolicyNotifyAsyncConfig {

    @Value("${policy.notify.core-size:2}")
    private int coreSize;

    @Value("${policy.notify.max-size:4}")
    private int maxSize;

    // Bounded queue: drops notifications silently when full rather than blocking the publisher.
    @Value("${policy.notify.queue-capacity:500}")
    private int queueCapacity;

    @Value("${policy.notify.connect-timeout-ms:100}")
    private int connectTimeoutMs;

    @Value("${policy.notify.read-timeout-ms:200}")
    private int readTimeoutMs;

    @Bean("policyNotifyExecutor")
    public Executor policyNotifyExecutor() {
        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
        executor.setCorePoolSize(coreSize);
        executor.setMaxPoolSize(maxSize);
        executor.setQueueCapacity(queueCapacity);
        executor.setThreadNamePrefix("policy-notify-");
        // DiscardPolicy: fire-and-forget — notifications are best-effort, never block the caller.
        executor.setRejectedExecutionHandler(new ThreadPoolExecutor.DiscardPolicy());
        executor.initialize();
        return executor;
    }

    @Bean("policyNotifyRestTemplate")
    public RestTemplate policyNotifyRestTemplate() {
        SimpleClientHttpRequestFactory factory = new SimpleClientHttpRequestFactory();
        factory.setConnectTimeout(connectTimeoutMs);
        factory.setReadTimeout(readTimeoutMs);
        return new RestTemplate(factory);
    }
}

