package com.fortinet.nac.ingestion.job;

import com.fortinet.nac.ingestion.job.event.PolicyStatusChangedEvent;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Qualifier;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.event.EventListener;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Component;
import org.springframework.web.client.RestTemplate;

import java.util.Map;

@Slf4j
@Component
@RequiredArgsConstructor
public class PolicyStatusNotifier {

    @Qualifier("policyNotifyRestTemplate")
    private final RestTemplate restTemplate;

    @Value("${policy.service.url}")
    private String policyServiceUrl;

    @Async("policyNotifyExecutor")
    @EventListener
    public void onStatusChanged(PolicyStatusChangedEvent event) {
        try {
            restTemplate.postForEntity(
                    policyServiceUrl + "/api/v1/internal/entity-status-changed",
                    Map.of(
                            "entityId", event.getEntityId(),
                            "stage", event.getStage(),
                            "fingerprint", event.getFingerprint()
                    ),
                    Void.class
            );
            log.debug("PolicyService notified, entityId={} stage={}", event.getEntityId(), event.getStage());
        } catch (Exception ex) {
            // Notification is best-effort; log and continue — never propagate back to Kafka consumer.
            log.warn("PolicyService notification failed, entityId={}: {}", event.getEntityId(), ex.getMessage());
        }
    }
}

